file.content:
/* Theme */
:root {
  --theme-hue: 204;
  --theme-saturation: 85%;
  --theme-lightness: 50%;
}

/* Sidebar */
:root {
  --sidebar-nav-indent: 0.7em;
  --sidebar-nav-pagelink-padding: 0.6em 0 0.6em 20px;
  --sidebar-name-font-weight: normal;
}

/* Sidebar again */
.sidebar-nav {
  font-size: 0.9em;
}

/* Code block */
:root {
  --code-font-size: calc(var(--font-size-m) * 0.9)
}

/* Giscus */
.giscus {
  margin: 1em 0;
}
.giscus-frame {
  max-width: var(--content-max-width);
  display: block;
  margin: 0 auto;
  padding: 0 45px;
}
